import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Signup() {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const navigate = useNavigate();

  const handleSignup = async (e) => {
    e.preventDefault();
    try {
      // FIX: Yahan 'formData' se values nikaal kar bhejni hain
      const response = await axios.post('http://127.0.0.1:8000/api/register', {
        username: formData.username,
        email: formData.email, // Email tabhi bhejein agar backend models mein hai

        password: formData.password
        // Agar backend email mang raha hai toh yahan email: formData.email bhi add karein
      });

      alert("Registration Successful!"); 
      navigate('/login');

    } catch (err) {
      if (err.response) {
        // Backend Error (422, 400, etc.)
        console.log("Backend Error:", err.response.data);
        alert("Error: " + JSON.stringify(err.response.data.detail));
      } else {
        // Network ya setup error
        console.log("Error Message:", err.message);
        alert("Connectivity Issue: " + err.message);
      }
    }
  };

  return (
    <div className="signup-container" style={{ padding: '50px', textAlign: 'center' }}>
      <h2>Naya Account Banayein</h2>
      <form onSubmit={handleSignup}>
        <input 
          type="text" 
          placeholder="Username" 
          value={formData.username}
          onChange={(e) => setFormData({...formData, username: e.target.value})} 
          required 
          style={{padding: '8px', margin: '5px', width: '250px'}} 
        /><br/>

        <input 
          type="email" 
          placeholder="Email" 
          value={formData.email}
          onChange={(e) => setFormData({...formData, email: e.target.value})} 
          required 
          style={{padding: '8px', margin: '5px', width: '250px'}} 
        /><br/>

        <input 
          type="password" 
          placeholder="Password" 
          value={formData.password}
          onChange={(e) => setFormData({...formData, password: e.target.value})} 
          required 
          style={{padding: '8px', margin: '5px', width: '250px'}} 
        /><br/>

        <button 
          type="submit" 
          style={{ backgroundColor: '#3498db', color: 'white', padding: '10px 20px', border: 'none', cursor: 'pointer', marginTop: '10px' }}
        >
          Register
        </button>
      </form>

      <p style={{ marginTop: '15px' }}>
        Pehle se account hai? <span style={{ color: '#3498db', cursor: 'pointer' }} onClick={() => navigate('/login')}>Login karein</span>
      </p>
    </div>
  );
}

export default Signup;
